import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { Eye, EyeOff, TrendingUp, Mail, Lock, User } from 'lucide-react';
import styles from './Auth.module.css';

export default function RegisterPage() {
  const [form, setForm] = useState({ name: '', email: '', password: '', confirm: '' });
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const { register } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    if (form.password !== form.confirm) {
      setError('Passwords do not match.');
      return;
    }
    if (form.password.length < 6) {
      setError('Password must be at least 6 characters.');
      return;
    }
    setLoading(true);
    try {
      await register(form.name, form.email, form.password);
      navigate('/dashboard');
    } catch (err) {
      setError(err.response?.data?.error || 'Registration failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const set = (key) => (e) => setForm({ ...form, [key]: e.target.value });

  return (
    <div className={styles.page}>
      <div className={styles.leftPanel}>
        <div className={styles.leftContent}>
          <div className={styles.logo}><div className={styles.logoIcon}>SV</div><span>StockVault</span></div>
          <h1 className={styles.headline}>Start your<br />trading journey.</h1>
          <p className={styles.subheadline}>
            Create a free account and get ₹1,00,000 in virtual money to practice trading real stocks — risk free.
          </p>
          <div className={styles.stats}>
            {[['Free', 'Forever'], ['₹1L', 'Virtual Cash'], ['Real-time', 'Market Data']].map(([v, l]) => (
              <div key={l} className={styles.stat}><strong>{v}</strong><span>{l}</span></div>
            ))}
          </div>
        </div>
        <div className={styles.chartBg}>
          <TrendingUp size={200} strokeWidth={0.5} color="rgba(255,255,255,0.06)" />
        </div>
      </div>

      <div className={styles.rightPanel}>
        <div className={styles.formCard}>
          <h2 className={styles.formTitle}>Create account</h2>
          <p className={styles.formSubtitle}>Join thousands of virtual traders</p>

          {error && <div className={styles.errorBox}>{error}</div>}

          <form onSubmit={handleSubmit} className={styles.form}>
            <div className={styles.field}>
              <label>Full Name</label>
              <div className={styles.inputWrap}>
                <User size={16} className={styles.inputIcon} />
                <input type="text" placeholder="Rahul Sharma" value={form.name} onChange={set('name')} required autoFocus />
              </div>
            </div>

            <div className={styles.field}>
              <label>Email</label>
              <div className={styles.inputWrap}>
                <Mail size={16} className={styles.inputIcon} />
                <input type="email" placeholder="rahul@example.com" value={form.email} onChange={set('email')} required />
              </div>
            </div>

            <div className={styles.field}>
              <label>Password</label>
              <div className={styles.inputWrap}>
                <Lock size={16} className={styles.inputIcon} />
                <input
                  type={showPassword ? 'text' : 'password'} placeholder="Min 6 characters"
                  value={form.password} onChange={set('password')} required
                />
                <button type="button" className={styles.eyeBtn} onClick={() => setShowPassword(!showPassword)}>
                  {showPassword ? <EyeOff size={16} /> : <Eye size={16} />}
                </button>
              </div>
            </div>

            <div className={styles.field}>
              <label>Confirm Password</label>
              <div className={styles.inputWrap}>
                <Lock size={16} className={styles.inputIcon} />
                <input
                  type={showPassword ? 'text' : 'password'} placeholder="Re-enter password"
                  value={form.confirm} onChange={set('confirm')} required
                />
              </div>
            </div>

            <button type="submit" className={styles.submitBtn} disabled={loading}>
              {loading && <span className={styles.spinner} />}
              {loading ? 'Creating account...' : 'Create Account — Get ₹1,00,000'}
            </button>
          </form>

          <p className={styles.switchAuth}>
            Already have an account? <Link to="/login">Sign in</Link>
          </p>
        </div>
      </div>
    </div>
  );
}
